const express = require('express');
const mongoose = require('mongoose');
const app = express();

app.use(express.json());

const isValidMongoDBQuery = (query) => {
  if (!query || typeof query !== 'object') return false;
  
  const allowedOperators = ['$eq', '$gt', '$gte', '$lt', '$lte', '$ne', '$in', '$nin', '$regex', '$options', '$or', '$and', '$not', '$elemMatch', '$exists', '$type', '$text', '$search', '$slice', '$sort'];
  
  const validateQuery = (obj) => {
    if (obj === null || typeof obj !== 'object') return true;
    
    for (const [key, value] of Object.entries(obj)) {
      if (key.startsWith('$') && !allowedOperators.includes(key)) {
        return false;
      }
      
      if (typeof value === 'object' && value !== null) {
        if (!validateQuery(value)) return false;
      }
    }
    
    return true;
  };
  
  return validateQuery(query);
};

const sanitizeQuery = (query) => {
  if (!query || typeof query !== 'object') return {};
  
  const sanitize = (obj) => {
    if (obj === null || typeof obj !== 'object') return obj;
    
    const result = {};
    for (const [key, value] of Object.entries(obj)) {
      if (key.startsWith('$') && !['$regex', '$options'].includes(key)) {
        if (typeof value === 'object' && value !== null) {
          result[key] = sanitize(value);
        } else {
          result[key] = value;
        }
      } else if (key.startsWith('$') && key === '$regex') {
        if (typeof value === 'string') {
          result[key] = value;
        }
      } else if (typeof value === 'object' && value !== null) {
        result[key] = sanitize(value);
      } else {
        result[key] = value;
      }
    }
    
    return result;
  };
  
  return sanitize(query);
};

app.post('/query', async (req, res) => {
  try {
    const { collection, query, options = {} } = req.body;
    
    if (!collection) {
      return res.status(400).json({ error: 'Collection name is required' });
    }
    
    if (!query || typeof query !== 'object') {
      return res.status(400).json({ error: 'Valid query object is required' });
    }
    
    if (!isValidMongoDBQuery(query)) {
      return res.status(400).json({ error: 'Invalid query operators' });
    }
    
    const sanitizedQuery = sanitizeQuery(query);
    
    const db = mongoose.connection;
    const collectionRef = db.collection(collection);
    
    const result = await collectionRef.find(sanitizedQuery, options);
    
    res.json({ data: result });
  } catch (error) {
    console.error('Query error:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

